  1	import * as React from 'react';
  2	import { useSafeK8sWatchResource } from '@odf/core/hooks';
  3	import { K8sResourceObj } from '@odf/core/types';
  4	import { useGetOCSHealth } from '@odf/ocs/hooks';
  5	import { StorageConsumerKind } from '@odf/shared';
  6	import { StorageConsumerModel } from '@odf/shared';
  7	import { ODF_OPERATOR } from '@odf/shared/constants';
  8	import HealthItem from '@odf/shared/dashboards/status-card/HealthItem';
  9	import { healthStateMap } from '@odf/shared/dashboards/status-card/states';
 10	import {
 11	  useCustomPrometheusPoll,
 12	  usePrometheusBasePath,
 13	} from '@odf/shared/hooks/custom-prometheus-poll';
 14	import { useWatchStorageSystems } from '@odf/shared/hooks/useWatchStorageSystems';
 15	import { StorageClusterModel } from '@odf/shared/models';
 16	import { getName, getNamespace } from '@odf/shared/selectors';
 17	import { ClusterServiceVersionKind } from '@odf/shared/types';
 18	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 19	import {
 20	  getGVK,
 21	  referenceForModel,
 22	  referenceForGroupVersionKind,
 23	  getOperatorHealthState,
 24	} from '@odf/shared/utils';
 25	import {
 26	  HealthState,
 27	  useFlag,
 28	  useK8sWatchResource,
 29	} from '@openshift-console/dynamic-plugin-sdk';
 30	import { useNavigate } from 'react-router-dom-v5-compat';
 31	import {
 32	  Gallery,
 33	  GalleryItem,
 34	  pluralize,
 35	  Card,
 36	  CardBody,
 37	  CardHeader,
 38	  CardTitle,
 39	} from '@patternfly/react-core';
 40	import { PROVIDER_MODE } from '../../../features';
 41	import { getVendorDashboardLinkFromMetrics } from '../../utils';
 42	import { StorageDashboard, STATUS_QUERIES } from '../queries';
 43	import StatusCardPopover from './status-card-popover';
 44	import { getAggregateClientHealthState, getClientText } from './utils';
 45	import '../../../style.scss';
 46	
 47	const operatorResource: K8sResourceObj = (ns) => ({
 48	  kind: 'operators.coreos.com~v1alpha1~ClusterServiceVersion',
 49	  namespace: ns,
 50	  isList: true,
 51	});
 52	
 53	export const StatusCard: React.FC = () => {
 54	  const { t } = useCustomTranslation();
 55	  const [csvData, csvLoaded, csvLoadError] =
 56	    useSafeK8sWatchResource<ClusterServiceVersionKind[]>(operatorResource);
 57	  const [systems, systemsLoaded, systemsLoadError] = useWatchStorageSystems();
 58	  const [healthData, healthError, healthLoading] = useCustomPrometheusPoll({
 59	    query: STATUS_QUERIES[StorageDashboard.HEALTH],
 60	    endpoint: 'api/v1/query' as any,
 61	    basePath: usePrometheusBasePath(),
 62	  });
 63	
 64	  const operator = csvData?.find((csv) =>
 65	    csv.metadata.name.startsWith(ODF_OPERATOR)
 66	  );
 67	  const operatorStatus = operator?.status?.phase;
 68	
 69	  // Todo(bipuladh): In 4.11 this should come in from an extension point
 70	  const ocsHealthStatuses = useGetOCSHealth(systems);
 71	
 72	  const parsedHealthData =
 73	    !healthError &&
 74	    !healthLoading &&
 75	    systemsLoaded &&
 76	    !systemsLoadError &&
 77	    healthData
 78	      ? healthData?.data?.result?.reduce((acc, curr) => {
 79	          const systemName = curr.metric.storage_system;
 80	          // ToDo (epic 4422): This equality check should work (for now) as "storage_system" will be unique,
 81	          // but moving forward add a label to metric for StorageSystem namespace as well and use that instead (update query as well).
 82	          // Equality check should be updated as well with "&&" condition on StorageSystem namespace.
 83	          const storageSystem = systems.find(
 84	            (system) => getName(system) === systemName
 85	          );
 86	          const systemNamespace = getNamespace(storageSystem);
 87	          const ocsHealthStatus =
 88	            ocsHealthStatuses[`${systemName}${systemNamespace}`];
 89	          const { apiGroup, apiVersion, kind } = getGVK(
 90	            storageSystem?.spec.kind
 91	          );
 92	          const systemKind =
 93	            referenceForGroupVersionKind(apiGroup)(apiVersion)(kind);
 94	          const systemData =
 95	            apiGroup === StorageClusterModel.apiGroup
 96	              ? {
 97	                  systemName,
 98	                  rawHealthData: ocsHealthStatus.rawHealthState,
 99	                  healthState: healthStateMap(ocsHealthStatus.rawHealthState),
100	                  link: getVendorDashboardLinkFromMetrics(
101	                    systemKind,
102	                    systemName,
103	                    systemNamespace,
104	                    ocsHealthStatus.errorComponent
105	                  ),
106	
107	                  ...(ocsHealthStatus.errorMessages
108	                    ? { extraTexts: ocsHealthStatus.errorMessages }
109	                    : {}),
110	                }
111	              : {
112	                  systemName,
113	                  rawHealthData: curr.value[1],
114	                  healthState: healthStateMap(curr.value[1]),
115	                  link: getVendorDashboardLinkFromMetrics(
116	                    systemKind,
117	                    systemName,
118	                    systemNamespace
119	                  ),
120	                };
121	          return [...acc, systemData];
122	        }, [])
123	      : [];
124	
125	  const healthySystems = parsedHealthData.filter(
126	    (item) => item.rawHealthData === '0'
127	  );
128	  const unHealthySystems = parsedHealthData.filter(
129	    (item) => item.rawHealthData !== '0'
130	  );
131	
132	  const operatorHealthStatus = getOperatorHealthState(
133	    operatorStatus,
134	    !csvLoaded,
135	    csvLoadError
136	  );
137	
138	  const isProviderMode = useFlag(PROVIDER_MODE);
139	
140	  const [clients, clientsLoaded, clientsLoadError] = useK8sWatchResource<
141	    StorageConsumerKind[]
142	  >({
143	    kind: referenceForModel(StorageConsumerModel),
144	    isList: true,
145	  });
146	
147	  const clientAggregateHealth = getAggregateClientHealthState(clients);
148	
149	  const navigate = useNavigate();
150	
151	  const redirectToListPage = React.useCallback(() => {
152	    navigate('/odf/storage-consumers');
153	  }, [navigate]);
154	
155	  return (
156	    <Card className="odfDashboard-card--height">
157	      <CardHeader>
158	        <CardTitle>{t('Status')}</CardTitle>
159	      </CardHeader>
160	      <CardBody>
161	        <Gallery className="odf-overview-status__health" hasGutter>
162	          <GalleryItem>
163	            <HealthItem
164	              title={t('Data Foundation')}
165	              state={operatorHealthStatus.state}
166	            />
167	          </GalleryItem>
168	          {healthySystems.length > 0 && (
169	            <GalleryItem>
170	              <HealthItem
171	                title={pluralize(healthySystems.length, t('Storage system'))}
172	                state={HealthState.OK}
173	              >
174	                <StatusCardPopover
175	                  resourceHealthMap={healthySystems}
176	                  firstColumnName={t('Storage system')}
177	                  secondColumnName={t('Health')}
178	                />
179	              </HealthItem>
180	            </GalleryItem>
181	          )}
182	          {unHealthySystems.length > 0 && (
183	            <GalleryItem>
184	              <HealthItem
185	                title={pluralize(unHealthySystems.length, 'Storage system')}
186	                state={HealthState.ERROR}
187	                maxWidth="35rem"
188	              >
189	                <StatusCardPopover
190	                  resourceHealthMap={unHealthySystems}
191	                  firstColumnName={t('Storage system')}
192	                  secondColumnName={t('Health')}
193	                />
194	              </HealthItem>
195	            </GalleryItem>
196	          )}
197	          {isProviderMode && clientsLoaded && !clientsLoadError && (
198	            <GalleryItem>
199	              <HealthItem
200	                title={t('Storage consumers')}
201	                state={clientAggregateHealth}
202	                onClick={redirectToListPage}
203	                details={getClientText(clients, t)}
204	              />
205	            </GalleryItem>
206	          )}
207	        </Gallery>
208	      </CardBody>
209	    </Card>
210	  );
211	};

